  return renderGroup({
    groupKey: group.repo_root,
    displayName: group.repo_name,
    icon: OCTOCAT_SVG,
    metaText: metaParts.join('<span class="meta-sep">\u00b7</span>'),
    cwd: group.repo_root,
    lastActive: group.last_active,
    timeline: group.timeline,
  }, filteredSessions);
}

function renderNonRepoGroup(group, filteredSessions) {
  var displayName = group.cwd.split("/").filter(Boolean).pop() || group.cwd;

  return renderGroup({
    groupKey: group.cwd,
    displayName: displayName,
    icon: "",
    metaText: '<span class="meta-count">' + filteredSessions.length + " session" + (filteredSessions.length !== 1 ? "s" : "") + '</span>',
    cwd: group.cwd,
    lastActive: group.last_active,
    timeline: group.timeline,
  }, filteredSessions);
}

