    var now = new Date();
    if (period === "Today") return new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
    if (period === "Yesterday") return new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1).getTime();
